1	import {
2	  Injectable,
3	  UnauthorizedException,
4	  ConflictException,
5	  NotFoundException,
6	  BadRequestException,
7	} from '@nestjs/common';
8	import { InjectRepository } from '@nestjs/typeorm';
9	import { Repository } from 'typeorm';
10	import { JwtService } from '@nestjs/jwt';
11	import { ConfigService } from '@nestjs/config';
12	import * as bcrypt from 'bcrypt';
13	import { User, UserStatus } from './entities/user.entity';
14	import { CreateUserDto } from './dto/create-user.dto';
15	import { UpdateUserDto } from './dto/update-user.dto';
16	import { EncryptionService } from '../common/encryption.service';
17	
18	@Injectable()
19	export class AuthService {
20	  private readonly bcryptRounds: number;
21	
22	  constructor(
23	    @InjectRepository(User)
24	    private readonly userRepository: Repository<User>,
25	    private readonly jwtService: JwtService,
26	    private readonly configService: ConfigService,
27	    private readonly encryptionService: EncryptionService,
28	  ) {
29	    this.bcryptRounds = this.configService.get<number>('bcrypt.rounds', 12);
30	  }
31	
32	  async login(
33	    username: string,
34	    password: string,
35	  ): Promise<{ accessToken: string; user: { id: string; username: string; role: string } }> {
36	    const user = await this.userRepository.findOne({ where: { username } });
37	    if (!user) {
38	      throw new UnauthorizedException('Invalid credentials');
39	    }
40	
41	    if (user.status === UserStatus.SUSPENDED) {
42	      throw new UnauthorizedException('Account is suspended');
43	    }
44	
45	    // Check lockout
46	    if (user.locked_until && user.locked_until > new Date()) {
47	      throw new UnauthorizedException(
48	        'Account is temporarily locked. Please try again later.',
49	      );
50	    }
51	
52	    // If lock has expired, reset it
53	    if (user.locked_until && user.locked_until <= new Date()) {
54	      user.locked_until = null;
55	      user.failed_login_count = 0;
56	      user.status = UserStatus.ACTIVE;
57	      await this.userRepository.save(user);
58	    }
59	
60	    const isPasswordValid = await bcrypt.compare(password, user.password_hash);
61	
62	    if (!isPasswordValid) {
63	      user.failed_login_count += 1;
64	
65	      if (user.failed_login_count >= 5) {
66	        user.locked_until = new Date(Date.now() + 15 * 60 * 1000); // 15 minutes
67	        user.status = UserStatus.LOCKED;
68	      }
69	
70	      await this.userRepository.save(user);
71	      throw new UnauthorizedException('Invalid credentials');
72	    }
73	
74	    // Reset failed login count on success
75	    if (user.failed_login_count > 0) {
76	      user.failed_login_count = 0;
77	      user.locked_until = null;
78	      user.status = UserStatus.ACTIVE;
79	      await this.userRepository.save(user);
80	    }
81	
82	    const payload = {
83	      sub: user.id,
84	      username: user.username,
85	      role: user.role,
86	      storeId: user.store_id,
87	    };
88	
89	    const accessToken = this.jwtService.sign(payload);
90	
91	    return {
92	      accessToken,
93	      user: {
94	        id: user.id,
95	        username: user.username,
96	        role: user.role,
97	      },
98	    };
99	  }
100	
101	  async validateUser(payload: { sub: string }): Promise<User | null> {
102	    return this.userRepository.findOne({ where: { id: payload.sub } });
103	  }
104	
105	  async createUser(dto: CreateUserDto): Promise<User> {
106	    const existing = await this.userRepository.findOne({
107	      where: { username: dto.username },
108	    });
109	    if (existing) {
110	      throw new ConflictException('Username already exists');
111	    }
112	
113	    const passwordHash = await bcrypt.hash(dto.password, this.bcryptRounds);
114	
115	    const user = this.userRepository.create({
116	      username: dto.username,
117	      password_hash: passwordHash,
118	      role: dto.role,
119	      store_id: dto.storeId || null,
120	    });
121	
122	    const saved = await this.userRepository.save(user);
123	
124	    // Remove password_hash from response
125	    delete (saved as any).password_hash;
126	    return saved;
127	  }
128	
129	  async updateUser(id: string, dto: UpdateUserDto): Promise<User> {
130	    const user = await this.userRepository.findOne({ where: { id } });
131	    if (!user) {
132	      throw new NotFoundException('User not found');
133	    }
134	
135	    if (dto.status !== undefined) {
136	      user.status = dto.status;
137	    }
138	    if (dto.role !== undefined) {
139	      user.role = dto.role;
140	    }
141	    if (dto.storeId !== undefined) {
142	      user.store_id = dto.storeId;
143	    }
144	    if (dto.notes !== undefined) {
145	      user.notes = dto.notes ? this.encryptionService.encrypt(dto.notes) : null;
146	    }
147	
148	    const saved = await this.userRepository.save(user);
149	    delete (saved as any).password_hash;
150	    return saved;
151	  }
152	
153	  async deleteUser(id: string): Promise<void> {
154	    const user = await this.userRepository.findOne({ where: { id } });
155	    if (!user) {
156	      throw new NotFoundException('User not found');
157	    }
158	    await this.userRepository.remove(user);
159	  }
160	
161	  async findAll(
162	    page: number = 1,
163	    limit: number = 20,
164	  ): Promise<{ data: User[]; total: number; page: number; limit: number }> {
165	    const [data, total] = await this.userRepository.findAndCount({
166	      skip: (page - 1) * limit,
167	      take: limit,
168	      order: { created_at: 'DESC' },
169	      select: [
170	        'id',
171	        'username',
172	        'role',
173	        'store_id',
174	        'status',
175	        'failed_login_count',
176	        'locked_until',
177	        'created_at',
178	        'updated_at',
179	      ],
180	    });
181	
182	    return { data, total, page, limit };
183	  }
184	
185	  async findById(id: string): Promise<User> {
186	    const user = await this.userRepository.findOne({
187	      where: { id },
188	      select: [
189	        'id',
190	        'username',
191	        'role',
192	        'store_id',
193	        'status',
194	        'failed_login_count',
195	        'locked_until',
196	        'notes',
197	        'created_at',
198	        'updated_at',
199	      ],
200	    });
201	    if (!user) {
202	      throw new NotFoundException('User not found');
203	    }
204	    // Decrypt notes if encrypted
205	    if (user.notes && this.encryptionService.isEncrypted(user.notes)) {
206	      user.notes = this.encryptionService.decrypt(user.notes);
207	    }
208	    return user;
209	  }
210	
211	  async updateNotes(id: string, notes: string): Promise<User> {
212	    const user = await this.userRepository.findOne({ where: { id } });
213	    if (!user) throw new NotFoundException('User not found');
214	    user.notes = this.encryptionService.encrypt(notes);
215	    return this.userRepository.save(user);
216	  }
217	
218	  async changePassword(
219	    userId: string,
220	    currentPassword: string,
221	    newPassword: string,
222	  ): Promise<void> {
223	    const user = await this.userRepository.findOne({ where: { id: userId } });
224	    if (!user) {
225	      throw new NotFoundException('User not found');
226	    }
227	
228	    const isCurrentValid = await bcrypt.compare(
229	      currentPassword,
230	      user.password_hash,
231	    );
232	    if (!isCurrentValid) {
233	      throw new BadRequestException('Current password is incorrect');
234	    }
235	
236	    user.password_hash = await bcrypt.hash(newPassword, this.bcryptRounds);
237	    await this.userRepository.save(user);
238	  }
239	}
240	
