10	
11	const ENTITY_TABLE_MAP: Record<string, string> = {
12	  products: 'products',
13	  orders: 'orders',
14	  questions: 'questions',
15	  users: 'users',
16	  inventory: 'inventory_lots',
17	};
18	
19	const ALL_ENTITY_TYPES = Object.keys(ENTITY_TABLE_MAP);
20	
21	@Injectable()
22	export class QualityService {
23	  private readonly logger = new Logger(QualityService.name);
24	
25	  constructor(
26	    @InjectRepository(DataQualityRule)
27	    private readonly ruleRepo: Repository<DataQualityRule>,
28	    @InjectRepository(DataQualityScore)
29	    private readonly scoreRepo: Repository<DataQualityScore>,
30	    private readonly dataSource: DataSource,
31	    private readonly configService: ConfigService,
32	    private readonly notificationsService: NotificationsService,
33	  ) {}
34	
35	  async createRule(dto: CreateQualityRuleDto): Promise<DataQualityRule> {
36	    const rule = this.ruleRepo.create({
37	      entity_type: dto.entityType,
38	      rule_type: dto.ruleType as RuleType,
39	      config: dto.config,
40	    });
41	    return this.ruleRepo.save(rule);
42	  }
43	
44	  async findRules(): Promise<DataQualityRule[]> {
45	    return this.ruleRepo.find({ where: { active: true } });
46	  }
47	
48	  async computeScore(entityType: string): Promise<DataQualityScore> {
49	    const rules = await this.ruleRepo.find({
50	      where: { entity_type: entityType, active: true },
51	    });
52	
53	    const tableName = ENTITY_TABLE_MAP[entityType];
54	    if (!tableName) {
55	      throw new Error(`Unknown entity type: ${entityType}`);
56	    }
57	
58	    const ruleScores: number[] = [];
59	
60	    for (const rule of rules) {
61	      const score = await this.evaluateRule(rule, tableName);
62	      ruleScores.push(score);
63	    }
64	
65	    const finalScore =
66	      ruleScores.length > 0
67	        ? ruleScores.reduce((a, b) => a + b, 0) / ruleScores.length
68	        : 100;
69	
70	    const scoreEntity = this.scoreRepo.create({
71	      entity_type: entityType,
72	      score: finalScore,
73	      computed_at: new Date(),
74	    });
75	
76	    return this.scoreRepo.save(scoreEntity);
77	  }
78	
79	  private async evaluateRule(
80	    rule: DataQualityRule,
81	    tableName: string,
82	  ): Promise<number> {
83	    switch (rule.rule_type) {
84	      case RuleType.COMPLETENESS:
85	        return this.evaluateCompleteness(rule, tableName);
86	      case RuleType.RANGE:
87	        return this.evaluateRange(rule, tableName);
88	      case RuleType.UNIQUENESS:
89	        return this.evaluateUniqueness(rule, tableName);
90	      default:
91	        return 100;
92	    }
93	  }
94	
95	  private async evaluateCompleteness(
96	    rule: DataQualityRule,
97	    tableName: string,
98	  ): Promise<number> {
99	    const fields: string[] = rule.config.fields || [];
100	    if (fields.length === 0) return 100;
101	
102	    const totalResult = await this.dataSource.query(
103	      `SELECT COUNT(*) as total FROM "${tableName}"`,
104	    );
105	    const total = parseInt(totalResult[0].total, 10);
106	    if (total === 0) return 100;
107	
108	    const conditions = fields
109	      .map(
110	        (f) =>
111	          `"${f}" IS NOT NULL AND CAST("${f}" AS TEXT) <> ''`,
112	      )
113	      .join(' AND ');
114	
115	    const completeResult = await this.dataSource.query(
116	      `SELECT COUNT(*) as complete FROM "${tableName}" WHERE ${conditions}`,
117	    );
118	    const complete = parseInt(completeResult[0].complete, 10);
119	
120	    return (complete / total) * 100;
121	  }
122	
123	  private async evaluateRange(
124	    rule: DataQualityRule,
125	    tableName: string,
126	  ): Promise<number> {
127	    const { column, min, max } = rule.config;
128	    if (!column) return 100;
129	
130	    const totalResult = await this.dataSource.query(
131	      `SELECT COUNT(*) as total FROM "${tableName}" WHERE "${column}" IS NOT NULL`,
132	    );
133	    const total = parseInt(totalResult[0].total, 10);
134	    if (total === 0) return 100;
135	
136	    let rangeCondition = `"${column}" IS NOT NULL`;
137	    if (min !== undefined) {
138	      rangeCondition += ` AND "${column}" >= ${Number(min)}`;
139	    }
140	    if (max !== undefined) {
141	      rangeCondition += ` AND "${column}" <= ${Number(max)}`;
142	    }
143	
144	    const inRangeResult = await this.dataSource.query(
145	      `SELECT COUNT(*) as in_range FROM "${tableName}" WHERE ${rangeCondition}`,
146	    );
147	    const inRange = parseInt(inRangeResult[0].in_range, 10);
148	
149	    return (inRange / total) * 100;
150	  }
151	
152	  private async evaluateUniqueness(
153	    rule: DataQualityRule,
154	    tableName: string,
155	  ): Promise<number> {
156	    const { column } = rule.config;
157	    if (!column) return 100;
158	
159	    const totalResult = await this.dataSource.query(
160	      `SELECT COUNT(*) as total FROM "${tableName}" WHERE "${column}" IS NOT NULL`,
161	    );
162	    const total = parseInt(totalResult[0].total, 10);
163	    if (total === 0) return 100;
164	
165	    const uniqueResult = await this.dataSource.query(
166	      `SELECT COUNT(DISTINCT "${column}") as unique_count FROM "${tableName}" WHERE "${column}" IS NOT NULL`,
167	    );
168	    const uniqueCount = parseInt(uniqueResult[0].unique_count, 10);
169	
170	    return (uniqueCount / total) * 100;
171	  }
172	
173	  async getScores(): Promise<DataQualityScore[]> {
174	    return this.dataSource.query(`
175	      SELECT DISTINCT ON (entity_type) *
176	      FROM data_quality_scores
177	      ORDER BY entity_type, computed_at DESC
178	    `);
179	  }
180	
181	  @Cron(CronExpression.EVERY_HOUR)
182	  async recomputeAllScores(): Promise<void> {
183	    this.logger.log('Recomputing all data quality scores');
184	    for (const entityType of ALL_ENTITY_TYPES) {
185	      try {
186	        await this.computeScore(entityType);
187	      } catch (err) {
188	        this.logger.error(
189	          `Failed to compute score for ${entityType}: ${(err as Error).message}`,
190	        );
191	      }
192	    }
193	  }
194	
195	  @Cron(CronExpression.EVERY_HOUR)
196	  async checkFreshness(): Promise<void> {
197	    const thresholdHours =
198	      this.configService.get<number>('stalenessThresholdHours') || 24;
199	
200	    for (const entityType of ALL_ENTITY_TYPES) {
201	      try {
202	        const tableName = ENTITY_TABLE_MAP[entityType];
203	        const result = await this.dataSource.query(`
204	          SELECT GREATEST(
205	            MAX(CASE WHEN EXISTS (
206	              SELECT 1 FROM information_schema.columns
207	              WHERE table_name = '${tableName}' AND column_name = 'updated_at'
208	            ) THEN updated_at ELSE NULL END),
209	            MAX(created_at)
210	          ) as last_activity
211	          FROM "${tableName}"
212	        `);
213	
214	        const lastActivity = result[0]?.last_activity;
215	        if (!lastActivity) continue;
216	
217	        const hoursSinceActivity =
218	          (Date.now() - new Date(lastActivity).getTime()) / (1000 * 60 * 60);
219	
220	        if (hoursSinceActivity > thresholdHours) {
221	          await this.notificationsService.createForAdmins(
222	            'data_staleness',
223	            `Data for "${entityType}" has not been updated in ${Math.round(hoursSinceActivity)} hours (threshold: ${thresholdHours}h).`,
224	          );
225	        }
226	      } catch (err) {
227	        this.logger.error(
228	          `Freshness check failed for ${entityType}: ${(err as Error).message}`,
229	        );
230	      }
231	    }
232	  }
233	}
