219	
220	  calculateDiscount(promotion: Promotion, orderTotalCents: number): number {
221	    if (
222	      promotion.min_order_cents !== null &&
223	      orderTotalCents < promotion.min_order_cents
224	    ) {
225	      return 0;
226	    }
227	
228	    if (promotion.discount_type === DiscountType.FIXED_CENTS) {
229	      return promotion.discount_value;
230	    }
231	
232	    // percentage
233	    return Math.floor((orderTotalCents * promotion.discount_value) / 100);
234	  }
235	
236	  async resolvePromotions(
237	    orderTotalCents: number,
238	    userId: string,
239	    storeId: string,
240	    couponCode?: string,
241	  ): Promise<ResolvedPromotion> {
242	    const now = new Date();
243	
244	    // 1. Find all active automatic promotions for the store within time window, not capped
245	    const qb = this.promotionRepo
246	      .createQueryBuilder('p')
247	      .where('p.store_id = :storeId', { storeId })
248	      .andWhere('p.active = true')
249	      .andWhere('(p.starts_at IS NULL OR p.starts_at <= :now)', { now })
250	      .andWhere('(p.ends_at IS NULL OR p.ends_at >= :now)', { now })
251	      .andWhere(
252	        '(p.redemption_cap IS NULL OR p.redemption_count < p.redemption_cap)',
253	      );
254	
255	    const autoPromotions = await qb.getMany();
256	
257	    // Filter out first_order promotions if user has prior orders
258	    const filteredPromotions: Promotion[] = [];
259	    for (const promo of autoPromotions) {
260	      if (promo.type === PromotionType.FIRST_ORDER) {
261	        // Check if user has any prior redeemed claims (proxy for orders)
262	        const priorClaim = await this.claimRepo.findOne({
263	          where: { user_id: userId, redeemed_at: MoreThanOrEqual(new Date(0)) },
264	        });
265	        if (priorClaim) {
266	          continue; // skip first_order promo if user has prior orders
267	        }
268	      }
269	      filteredPromotions.push(promo);
270	    }
271	
272	    // 3. Sort by priority DESC
273	    filteredPromotions.sort((a, b) => {
274	      if (b.priority !== a.priority) return b.priority - a.priority;
275	      // 4. Tie-break: highest effective discount
276	      const discA = this.calculateDiscount(a, orderTotalCents);
277	      const discB = this.calculateDiscount(b, orderTotalCents);
278	      if (discB !== discA) return discB - discA;
279	      // 5. Still tied: lower UUID wins
280	      return a.id < b.id ? -1 : 1;
281	    });
282	
283	    const bestAutoPromo = filteredPromotions.length > 0 ? filteredPromotions[0] : null;
284	
285	    // 2. If couponCode provided, validate coupon and get linked promotion
286	    let selectedCoupon: Coupon | null = null;
287	    let couponPromotion: Promotion | null = null;
288	
289	    if (couponCode) {
290	      const coupon = await this.couponRepo.findOne({
291	        where: { code: couponCode },
292	        relations: ['promotion'],
293	      });
294	
295	      if (
296	        coupon &&
297	        coupon.status === CouponStatus.ACTIVE &&
298	        (!coupon.starts_at || coupon.starts_at <= now) &&
299	        (!coupon.ends_at || coupon.ends_at >= now)
300	      ) {
301	        selectedCoupon = coupon;
302	        couponPromotion = coupon.promotion;
303	      }
304	    }
305	
306	    // 8. Max one coupon + one automatic promotion per order
307	    let totalDiscount = 0;
308	    let selectedPromotion: Promotion | null = null;
309	
310	    if (bestAutoPromo) {
311	      const autoDiscount = this.calculateDiscount(bestAutoPromo, orderTotalCents);
312	      if (autoDiscount > 0) {
313	        totalDiscount += autoDiscount;
314	        selectedPromotion = bestAutoPromo;
315	      }
316	    }
317	
318	    if (couponPromotion) {
319	      const couponDiscount = this.calculateDiscount(couponPromotion, orderTotalCents);
320	      if (couponDiscount > 0) {
321	        totalDiscount += couponDiscount;
322	        // If no auto promo was selected, the coupon promotion becomes the selected one
323	        if (!selectedPromotion) {
324	          selectedPromotion = couponPromotion;
325	        }
326	      }
327	    }
328	
329	    return {
330	      selectedPromotion,
331	      selectedCoupon,
332	      totalDiscount,
333	    };
334	  }
335	
336	  @Cron(CronExpression.EVERY_HOUR)
337	  async handleExpiredCoupons(): Promise<void> {
338	    const now = new Date();
339	    const result = await this.couponRepo
340	      .createQueryBuilder()
341	      .update(Coupon)
342	      .set({ status: CouponStatus.EXPIRED })
343	      .where('status = :status', { status: CouponStatus.ACTIVE })
344	      .andWhere('ends_at IS NOT NULL')
345	      .andWhere('ends_at < :now', { now })
346	      .execute();
347	
348	    if (result.affected && result.affected > 0) {
349	      this.logger.log(`Expired ${result.affected} coupons`);
350	    }
351	  }
352	}
