28	    storeId?: string,
29	  ): Promise<Question> {
30	    const question = this.questionRepo.create({
31	      type: dto.type,
32	      body: dto.body,
33	      created_by: userId,
34	      store_id: storeId ?? null,
35	    });
36	
37	    const savedQuestion = await this.questionRepo.save(question);
38	
39	    if (dto.type === QuestionType.OBJECTIVE && dto.options?.length) {
40	      const options = dto.options.map((opt) =>
41	        this.optionRepo.create({
42	          question_id: savedQuestion.id,
43	          body: opt.body,
44	          is_correct: opt.isCorrect,
45	        }),
46	      );
47	      savedQuestion.options = await this.optionRepo.save(options);
