117	  async addExplanation(
118	    questionId: string,
119	    body: string,
120	    userId: string,
121	  ): Promise<QuestionExplanation> {
122	    const question = await this.questionRepo.findOne({
123	      where: { id: questionId },
124	    });
125	    if (!question) {
126	      throw new NotFoundException('Question not found');
127	    }
128	
129	    // Auto-increment version_number
130	    const latest = await this.explanationRepo
131	      .createQueryBuilder('e')
132	      .where('e.question_id = :questionId', { questionId })
133	      .orderBy('e.version_number', 'DESC')
134	      .getOne();
135	
136	    const nextVersion = latest ? latest.version_number + 1 : 1;
137	
138	    const explanation = this.explanationRepo.create({
139	      question_id: questionId,
140	      version_number: nextVersion,
141	      body,
142	      created_by: userId,
143	    });
144	
145	    return this.explanationRepo.save(explanation);
146	  }
