155	  async bulkImport(
156	    questions: CreateQuestionDto[],
157	    userId: string,
158	    storeId?: string,
159	  ): Promise<{ count: number }> {
160	    let count = 0;
161	
162	    await this.dataSource.transaction(async (manager) => {
163	      for (const dto of questions) {
164	        const question = manager.create(Question, {
165	          type: dto.type,
166	          body: dto.body,
167	          created_by: userId,
168	          store_id: storeId ?? null,
169	        });
170	
171	        const savedQuestion = await manager.save(question);
172	
173	        if (dto.type === QuestionType.OBJECTIVE && dto.options?.length) {
174	          const options = dto.options.map((opt) =>
175	            manager.create(QuestionOption, {
176	              question_id: savedQuestion.id,
177	              body: opt.body,
178	              is_correct: opt.isCorrect,
179	            }),
180	          );
181	          await manager.save(options);
182	        }
183	
184	        count++;
185	      }
186	    });
187	
188	    return { count };
189	  }
