191	  async bulkExport(filters?: {
192	    type?: QuestionType;
193	    status?: QuestionStatus;
194	    storeId?: string;
195	  }): Promise<string> {
196	    const questions = await this.findAll(filters);
197	
198	    const header = 'id,type,body,status,options';
199	    const rows = questions.map((q) => {
200	      const escapedBody = `"${q.body.replace(/"/g, '""')}"`;
201	      const optionsJson = q.options?.length
202	        ? `"${JSON.stringify(
203	            q.options.map((o) => ({ body: o.body, isCorrect: o.is_correct })),
204	          ).replace(/"/g, '""')}"`
205	        : '""';
206	      return `${q.id},${q.type},${escapedBody},${q.status},${optionsJson}`;
207	    });
208	
209	    return [header, ...rows].join('\n');
210	  }
211	
212	  async getWrongAnswerStats(
213	    questionId: string,
214	  ): Promise<Record<string, number>> {
215	    const results = await this.dataSource
216	      .createQueryBuilder()
217	      .select('aa.selected_option_id', 'optionId')
218	      .addSelect('COUNT(*)::int', 'count')
219	      .from('attempt_answers', 'aa')
220	      .where('aa.question_id = :questionId', { questionId })
221	      .andWhere('aa.is_correct = false')
222	      .groupBy('aa.selected_option_id')
223	      .getRawMany();
224	
225	    const stats: Record<string, number> = {};
226	    for (const row of results) {
227	      if (row.optionId) {
228	        stats[row.optionId] = row.count;
229	      }
230	    }
231	    return stats;
232	  }
