197	
198	    const header = 'id,type,body,status,options';
199	    const rows = questions.map((q) => {
200	      const escapedBody = `"${q.body.replace(/"/g, '""')}"`;
201	      const optionsJson = q.options?.length
202	        ? `"${JSON.stringify(
203	            q.options.map((o) => ({ body: o.body, isCorrect: o.is_correct })),
204	          ).replace(/"/g, '""')}"`
205	        : '""';
206	      return `${q.id},${q.type},${escapedBody},${q.status},${optionsJson}`;
207	    });
208	
209	    return [header, ...rows].join('\n');
210	  }
