214	  ): Promise<Record<string, number>> {
215	    const results = await this.dataSource
216	      .createQueryBuilder()
217	      .select('aa.selected_option_id', 'optionId')
218	      .addSelect('COUNT(*)::int', 'count')
219	      .from('attempt_answers', 'aa')
220	      .where('aa.question_id = :questionId', { questionId })
221	      .andWhere('aa.is_correct = false')
222	      .groupBy('aa.selected_option_id')
223	      .getRawMany();
224	
225	    const stats: Record<string, number> = {};
226	    for (const row of results) {
227	      if (row.optionId) {
228	        stats[row.optionId] = row.count;
229	      }
230	    }
231	    return stats;
232	  }
