49	    const rules = await this.ruleRepo.find({
50	      where: { entity_type: entityType, active: true },
51	    });
52	
53	    const tableName = ENTITY_TABLE_MAP[entityType];
54	    if (!tableName) {
55	      throw new Error(`Unknown entity type: ${entityType}`);
56	    }
57	
58	    const ruleScores: number[] = [];
