60	    for (const rule of rules) {
61	      const score = await this.evaluateRule(rule, tableName);
62	      ruleScores.push(score);
63	    }
64	
65	    const finalScore =
66	      ruleScores.length > 0
67	        ? ruleScores.reduce((a, b) => a + b, 0) / ruleScores.length
68	        : 100;
