79	  private async evaluateRule(
80	    rule: DataQualityRule,
81	    tableName: string,
82	  ): Promise<number> {
83	    switch (rule.rule_type) {
84	      case RuleType.COMPLETENESS:
85	        return this.evaluateCompleteness(rule, tableName);
86	      case RuleType.RANGE:
87	        return this.evaluateRange(rule, tableName);
88	      case RuleType.UNIQUENESS:
89	        return this.evaluateUniqueness(rule, tableName);
90	      default:
91	        return 100;
92	    }
93	  }
