123	  private async evaluateRange(
124	    rule: DataQualityRule,
125	    tableName: string,
126	  ): Promise<number> {
127	    const { column, min, max } = rule.config;
128	    if (!column) return 100;
129	
130	    const totalResult = await this.dataSource.query(
131	      `SELECT COUNT(*) as total FROM "${tableName}" WHERE "${column}" IS NOT NULL`,
132	    );
133	    const total = parseInt(totalResult[0].total, 10);
134	    if (total === 0) return 100;
135	
136	    let rangeCondition = `"${column}" IS NOT NULL`;
137	    if (min !== undefined) {
138	      rangeCondition += ` AND "${column}" >= ${Number(min)}`;
139	    }
140	    if (max !== undefined) {
141	      rangeCondition += ` AND "${column}" <= ${Number(max)}`;
142	    }
143	
144	    const inRangeResult = await this.dataSource.query(
145	      `SELECT COUNT(*) as in_range FROM "${tableName}" WHERE ${rangeCondition}`,
146	    );
147	    const inRange = parseInt(inRangeResult[0].in_range, 10);
148	
149	    return (inRange / total) * 100;
150	  }
