152	  private async evaluateUniqueness(
153	    rule: DataQualityRule,
154	    tableName: string,
155	  ): Promise<number> {
156	    const { column } = rule.config;
157	    if (!column) return 100;
158	
159	    const totalResult = await this.dataSource.query(
160	      `SELECT COUNT(*) as total FROM "${tableName}" WHERE "${column}" IS NOT NULL`,
161	    );
162	    const total = parseInt(totalResult[0].total, 10);
163	    if (total === 0) return 100;
164	
165	    const uniqueResult = await this.dataSource.query(
166	      `SELECT COUNT(DISTINCT "${column}") as unique_count FROM "${tableName}" WHERE "${column}" IS NOT NULL`,
167	    );
168	    const uniqueCount = parseInt(uniqueResult[0].unique_count, 10);
169	
170	    return (uniqueCount / total) * 100;
171	  }
