200	    for (const entityType of ALL_ENTITY_TYPES) {
201	      try {
202	        const tableName = ENTITY_TABLE_MAP[entityType];
203	        const result = await this.dataSource.query(`
204	          SELECT GREATEST(
205	            MAX(CASE WHEN EXISTS (
206	              SELECT 1 FROM information_schema.columns
207	              WHERE table_name = '${tableName}' AND column_name = 'updated_at'
208	            ) THEN updated_at ELSE NULL END),
209	            MAX(created_at)
210	          ) as last_activity
211	          FROM "${tableName}"
