      expiresAt,
      context?.ipAddress,
      context?.userAgent,
    );

    const payload = {
      sub: user.id,
      username: user.username,
      role: user.role,
      storeId: user.store_id,
      jti,
    };

    const accessToken = this.jwtService.sign(payload);

    return {
      accessToken,
      user: {
        id: user.id,
        username: user.username,
        role: user.role,
      },
    };
