  @ApiOperation({ summary: 'User login' })
  @ApiResponse({ status: 200, description: 'Login successful' })
  @ApiResponse({ status: 401, description: 'Invalid credentials or locked' })
  async login(@Body() dto: LoginDto, @Req() req: any) {
    const ipAddress =
      (req.headers?.['x-forwarded-for'] as string)?.split(',')[0]?.trim() ||
      req.ip ||
      req.socket?.remoteAddress ||
      undefined;
    const userAgent = (req.headers?.['user-agent'] as string) || undefined;
    const result = await this.authService.login(dto.username, dto.password, {
      ipAddress,
      userAgent,
    });
    await this.auditService.log(
      result.user.id,
      'login',
      'user',
      result.user.id,
      undefined,
      req.traceId,
    );
    return result;
  }

  @Post('logout')
  @HttpCode(HttpStatus.NO_CONTENT)
  @ApiBearerAuth()
  @ApiOperation({ summary: 'Logout — invalidates current JWT' })
  @ApiResponse({ status: 204, description: 'Logged out' })
  async logout(@CurrentUser() user: any, @Req() req: any) {
    await this.authService.logout(user.id, user.jti);
    await this.auditService.log(
      user.id,
      'logout',
      'user',
      user.id,
      undefined,
      req.traceId,
    );
    return;
  }"}

