1	import {
2	  UnauthorizedException,
3	  ConflictException,
4	  NotFoundException,
5	  BadRequestException,
6	} from '@nestjs/common';
7	import * as bcrypt from 'bcrypt';
8	import { AuthService } from '../src/auth/auth.service';
9	import { UserRole, UserStatus } from '../src/auth/entities/user.entity';
10	
11	// ---------------------------------------------------------------------------
12	// Helpers
13	// ---------------------------------------------------------------------------
14	
15	function makeUser(overrides: Record<string, any> = {}) {
16	  return {
17	    id: 'user-uuid-1',
18	    username: 'testuser',
19	    password_hash: '$2b$12$hashedpassword',
20	    role: UserRole.STORE_ADMIN,
21	    store_id: 'store-uuid-1',
22	    status: UserStatus.ACTIVE,
23	    failed_login_count: 0,
24	    locked_until: null,
25	    notes: null,
26	    created_at: new Date('2025-01-01'),
27	    updated_at: new Date('2025-01-01'),
28	    ...overrides,
29	  };
30	}
31	
32	// ---------------------------------------------------------------------------
33	// Mock factories
34	// ---------------------------------------------------------------------------
35	
36	function createMockRepository() {
37	  return {
38	    findOne: jest.fn(),
39	    findAndCount: jest.fn(),
40	    create: jest.fn((dto: any) => ({ ...dto })),
41	    save: jest.fn((entity: any) => Promise.resolve({ ...entity })),
42	    remove: jest.fn(),
43	  };
44	}
45	
46	function createMockJwtService() {
47	  return {
48	    sign: jest.fn(() => 'signed-jwt-token'),
49	    verify: jest.fn(() => ({ sub: 'user-uuid-1', username: 'testuser', role: 'store_admin' })),
50	  };
51	}
52	
53	function createMockConfigService() {
54	  return {
55	    get: jest.fn((key: string, defaultVal?: any) => {
56	      if (key === 'bcrypt.rounds') return 10;
57	      return defaultVal;
58	    }),
59	  };
60	}
61	
62	// ---------------------------------------------------------------------------
63	// Tests
64	// ---------------------------------------------------------------------------
65	
66	describe('AuthService', () => {
67	  let service: AuthService;
68	  let userRepo: ReturnType<typeof createMockRepository>;
69	  let jwtService: ReturnType<typeof createMockJwtService>;
70	  let configService: ReturnType<typeof createMockConfigService>;
71	
72	  beforeEach(() => {
73	    userRepo = createMockRepository();
74	    jwtService = createMockJwtService();
75	    configService = createMockConfigService();
76	
77	    service = new AuthService(
78	      userRepo as any,
79	      jwtService as any,
80	      configService as any,
81	    );
82	  });
83	
84	  // -----------------------------------------------------------------------
85	  // 1. Password hashing: bcrypt hash and verify
86	  // -----------------------------------------------------------------------
87	  describe('password hashing (bcrypt)', () => {
88	    it('should hash a password and verify it correctly', async () => {
89	      const plain = 'MySecretP@ss1';
90	      const hash = await bcrypt.hash(plain, 10);
91	
92	      expect(hash).not.toBe(plain);
93	      expect(await bcrypt.compare(plain, hash)).toBe(true);
94	      expect(await bcrypt.compare('wrongpassword', hash)).toBe(false);
95	    });
96	  });
97	
98	  // -----------------------------------------------------------------------
99	  // 2. JWT sign and verify
100	  // -----------------------------------------------------------------------
101	  describe('JWT sign and verify', () => {
102	    it('sign returns a token string', () => {
103	      const token = jwtService.sign({ sub: 'id', username: 'u', role: 'store_admin' });
104	      expect(token).toBe('signed-jwt-token');
105	      expect(jwtService.sign).toHaveBeenCalled();
106	    });
107	
108	    it('verify decodes the payload', () => {
109	      const payload = jwtService.verify('signed-jwt-token');
110	      expect(payload).toEqual(expect.objectContaining({ sub: 'user-uuid-1' }));
111	      expect(jwtService.verify).toHaveBeenCalledWith('signed-jwt-token');
112	    });
113	  });
114	
115	  // -----------------------------------------------------------------------
116	  // 3. Login success returns accessToken + user object
117	  // -----------------------------------------------------------------------
118	  describe('login', () => {
119	    it('should return accessToken and user on valid credentials', async () => {
120	      const plainPassword = 'correctPassword';
121	      const hashed = await bcrypt.hash(plainPassword, 10);
122	      const user = makeUser({ password_hash: hashed });
123	
124	      userRepo.findOne.mockResolvedValue(user);
125	
126	      const result = await service.login('testuser', plainPassword);
127	
128	      expect(result).toEqual({
129	        accessToken: 'signed-jwt-token',
130	        user: {
131	          id: user.id,
132	          username: user.username,
133	          role: user.role,
134	        },
135	      });
136	      expect(jwtService.sign).toHaveBeenCalledWith(
137	        expect.objectContaining({
138	          sub: user.id,
139	          username: user.username,
140	          role: user.role,
141	          storeId: user.store_id,
142	        }),
143	      );
144	    });
145	
146	    // ---------------------------------------------------------------------
147	    // 4. Login: wrong password -> UnauthorizedException
148	    // ---------------------------------------------------------------------
149	    it('should throw UnauthorizedException for wrong password', async () => {
150	      const hashed = await bcrypt.hash('correctPassword', 10);
151	      const user = makeUser({ password_hash: hashed });
152	
153	      userRepo.findOne.mockResolvedValue(user);
154	
155	      await expect(service.login('testuser', 'wrongPassword')).rejects.toThrow(
156	        UnauthorizedException,
157	      );
158	    });
159	
160	    it('should throw UnauthorizedException for non-existent user', async () => {
161	      userRepo.findOne.mockResolvedValue(null);
162	
163	      await expect(service.login('nobody', 'any')).rejects.toThrow(
164	        UnauthorizedException,
165	      );
166	    });
167	
168	    // ---------------------------------------------------------------------
169	    // 5. Login: account locked (locked_until in future) -> UnauthorizedException
170	    // ---------------------------------------------------------------------
171	    it('should throw UnauthorizedException when account is locked', async () => {
172	      const user = makeUser({
173	        locked_until: new Date(Date.now() + 60 * 60 * 1000), // 1 hour in future
174	        status: UserStatus.LOCKED,
175	      });
176	      userRepo.findOne.mockResolvedValue(user);
177	
178	      await expect(service.login('testuser', 'any')).rejects.toThrow(
179	        UnauthorizedException,
180	      );
181	      await expect(service.login('testuser', 'any')).rejects.toThrow(
182	        /temporarily locked/,
183	      );
184	    });
185	
186	    // ---------------------------------------------------------------------
187	    // 6. Login: 5 failed attempts -> account gets locked
188	    // ---------------------------------------------------------------------
189	    it('should lock the account after 5 failed login attempts', async () => {
190	      const hashed = await bcrypt.hash('correctPassword', 10);
191	      const user = makeUser({ password_hash: hashed, failed_login_count: 4 });
192	
193	      userRepo.findOne.mockResolvedValue(user);
194	
195	      await expect(service.login('testuser', 'wrongPassword')).rejects.toThrow(
196	        UnauthorizedException,
197	      );
198	
199	      // After the 5th failure the save should have set locked_until and LOCKED status
200	      expect(userRepo.save).toHaveBeenCalledWith(
201	        expect.objectContaining({
202	          failed_login_count: 5,
203	          status: UserStatus.LOCKED,
204	        }),
205	      );
206	      // locked_until should be roughly 15 min from now
207	      const savedArg = userRepo.save.mock.calls[0][0];
208	      expect(savedArg.locked_until).toBeInstanceOf(Date);
209	      const diff = savedArg.locked_until.getTime() - Date.now();
210	      expect(diff).toBeGreaterThan(14 * 60 * 1000);
211	      expect(diff).toBeLessThanOrEqual(15 * 60 * 1000 + 1000);
212	    });
213	
214	    // ---------------------------------------------------------------------
215	    // 7. Login: lock expired -> resets on next attempt
216	    // ---------------------------------------------------------------------
217	    it('should reset lock and allow login when lock has expired', async () => {
218	      const plainPassword = 'correctPassword';
219	      const hashed = await bcrypt.hash(plainPassword, 10);
220	      const user = makeUser({
221	        password_hash: hashed,
222	        locked_until: new Date(Date.now() - 1000), // expired
223	        failed_login_count: 5,
224	        status: UserStatus.LOCKED,
225	      });
226	
227	      userRepo.findOne.mockResolvedValue(user);
228	      // After the lock-reset save, the user object is mutated in place
229	      userRepo.save.mockImplementation((entity: any) => Promise.resolve(entity));
230	
231	      const result = await service.login('testuser', plainPassword);
232	
233	      expect(result.accessToken).toBe('signed-jwt-token');
234	      // The first save call should reset the lock fields
235	      const firstSaveArg = userRepo.save.mock.calls[0][0];
236	      expect(firstSaveArg.locked_until).toBeNull();
237	      expect(firstSaveArg.failed_login_count).toBe(0);
238	      expect(firstSaveArg.status).toBe(UserStatus.ACTIVE);
239	    });
240	
241	    // ---------------------------------------------------------------------
242	    // 8. Login: suspended account -> UnauthorizedException
243	    // ---------------------------------------------------------------------
244	    it('should throw UnauthorizedException for suspended account', async () => {
245	      const user = makeUser({ status: UserStatus.SUSPENDED });
246	      userRepo.findOne.mockResolvedValue(user);
247	
248	      await expect(service.login('testuser', 'any')).rejects.toThrow(
249	        UnauthorizedException,
250	      );
251	      await expect(service.login('testuser', 'any')).rejects.toThrow(
252	        /suspended/,
253	      );
254	    });
255	
256	    // Successful login resets failed_login_count
257	    it('should reset failed_login_count on successful login after previous failures', async () => {
258	      const plainPassword = 'correctPassword';
259	      const hashed = await bcrypt.hash(plainPassword, 10);
260	      const user = makeUser({ password_hash: hashed, failed_login_count: 3 });
261	
262	      userRepo.findOne.mockResolvedValue(user);
263	      userRepo.save.mockImplementation((entity: any) => Promise.resolve(entity));
264	
265	      await service.login('testuser', plainPassword);
266	
267	      expect(userRepo.save).toHaveBeenCalledWith(
268	        expect.objectContaining({
269	          failed_login_count: 0,
270	          locked_until: null,
271	          status: UserStatus.ACTIVE,
272	        }),
273	      );
274	    });
275	  });
276	
277	  // -----------------------------------------------------------------------
278	  // 9. Role check logic: platform_admin, store_admin, content_reviewer, auditor
279	  // -----------------------------------------------------------------------
280	  describe('role check logic', () => {
281	    const roles = [
282	      UserRole.PLATFORM_ADMIN,
283	      UserRole.STORE_ADMIN,
284	      UserRole.CONTENT_REVIEWER,
285	      UserRole.AUDITOR,
286	    ] as const;
287	
288	    it.each(roles)(
289	      'should include correct role "%s" in JWT payload on login',
290	      async (role) => {
291	        const plainPassword = 'pass123';
292	        const hashed = await bcrypt.hash(plainPassword, 10);
293	        const user = makeUser({ password_hash: hashed, role });
294	
295	        userRepo.findOne.mockResolvedValue(user);
296	
297	        await service.login('testuser', plainPassword);
298	
299	        expect(jwtService.sign).toHaveBeenCalledWith(
300	          expect.objectContaining({ role }),
301	        );
302	      },
303	    );
304	
305	    it('should return the role in the user object from login', async () => {
306	      const plainPassword = 'pass123';
307	      const hashed = await bcrypt.hash(plainPassword, 10);
308	
309	      for (const role of roles) {
310	        const user = makeUser({ password_hash: hashed, role });
311	        userRepo.findOne.mockResolvedValue(user);
312	        jwtService.sign.mockClear();
313	
314	        const result = await service.login('testuser', plainPassword);
315	        expect(result.user.role).toBe(role);
316	      }
317	    });
318	  });
319	
320	  // -----------------------------------------------------------------------
321	  // 10. createUser: hashes password, creates user
