  const dataSource = {
    transaction: jest.fn(async (cb: any) => cb(fakeManager)),
  };

  const service = new PromotionsService(
    promotionRepo as any,
    couponRepo as any,
    claimRepo as any,
    dataSource as any,
  );

  return { service, promotionRepo, couponRepo, claimRepo, dataSource };
