10	@Catch()
11	export class GlobalExceptionFilter implements ExceptionFilter {
12	  catch(exception: unknown, host: ArgumentsHost) {
13	    const ctx = host.switchToHttp();
14	    const response = ctx.getResponse<Response>();
15	    const request = ctx.getRequest<Request>();
16	    const traceId = (request as any).traceId || 'unknown';
17	
18	    let status = HttpStatus.INTERNAL_SERVER_ERROR;
19	    let code = 'INTERNAL_ERROR';
20	    let message = 'Internal server error';
21	
22	    if (exception instanceof HttpException) {
23	      status = exception.getStatus();
24	      const exResponse = exception.getResponse();
25	      if (typeof exResponse === 'object' && exResponse !== null) {
26	        const r = exResponse as any;
27	        code = r.code || this.statusToCode(status);
28	        message = r.message || exception.message;
29	        if (Array.isArray(message)) {
30	          message = message.join('; ');
31	        }
32	      } else {
33	        code = this.statusToCode(status);
34	        message = exception.message;
35	      }
36	    }
37	
38	    response.status(status).json({
39	      statusCode: status,
40	      code,
41	      message,
42	      traceId,
43	    });
44	  }
45	
46	  private statusToCode(status: number): string {
47	    switch (status) {
48	      case 400: return 'VALIDATION_ERROR';
49	      case 401: return 'UNAUTHORIZED';
50	      case 403: return 'FORBIDDEN';
51	      case 404: return 'NOT_FOUND';
52	      case 409: return 'CONFLICT';
53	      default: return 'INTERNAL_ERROR';
54	    }
