1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	} from '@nestjs/common';
6	import { InjectRepository } from '@nestjs/typeorm';
7	import { Repository, DataSource } from 'typeorm';
8	import { Paper } from './entities/paper.entity';
9	import { PaperQuestion } from './entities/paper-question.entity';
10	import { Attempt, AttemptStatus } from './entities/attempt.entity';
11	import { AttemptAnswer } from './entities/attempt-answer.entity';
12	import { Question, QuestionStatus, QuestionType } from '../questions/entities/question.entity';
13	import { QuestionOption } from '../questions/entities/question-option.entity';
14	import { GeneratePaperDto } from './dto/generate-paper.dto';
15	import { SubmitAnswerDto } from './dto/submit-attempt.dto';
16	
17	@Injectable()
18	export class AssessmentsService {
19	  constructor(
20	    @InjectRepository(Paper)
21	    private readonly paperRepo: Repository<Paper>,
22	    @InjectRepository(PaperQuestion)
23	    private readonly paperQuestionRepo: Repository<PaperQuestion>,
24	    @InjectRepository(Attempt)
25	    private readonly attemptRepo: Repository<Attempt>,
26	    @InjectRepository(AttemptAnswer)
27	    private readonly answerRepo: Repository<AttemptAnswer>,
28	    @InjectRepository(Question)
29	    private readonly questionRepo: Repository<Question>,
30	    @InjectRepository(QuestionOption)
31	    private readonly optionRepo: Repository<QuestionOption>,
32	    private readonly dataSource: DataSource,
33	  ) {}
34	
35	  async generatePaper(
36	    dto: GeneratePaperDto,
37	    userId: string,
38	    storeId?: string,
39	  ): Promise<Paper> {
40	    const { generationRule } = dto;
41	    let questions: Question[];
42	
43	    if (generationRule.type === 'random') {
44	      const count = generationRule.count ?? 10;
45	      const qb = this.questionRepo
46	        .createQueryBuilder('q')
47	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
48	
49	      if (storeId) {
50	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
51	          storeId,
52	        });
53	      }
54	
55	      questions = await qb
56	        .orderBy('RANDOM()')
57	        .limit(count)
58	        .getMany();
59	    } else {
60	      // rule-based
61	      const qb = this.questionRepo
62	        .createQueryBuilder('q')
63	        .where('q.status = :status', { status: QuestionStatus.APPROVED });
64	
65	      if (storeId) {
66	        qb.andWhere('(q.store_id = :storeId OR q.store_id IS NULL)', {
67	          storeId,
68	        });
69	      }
70	
71	      const filters = generationRule.filters ?? {};
72	      if (filters.type) {
73	        qb.andWhere('q.type = :type', { type: filters.type });
74	      }
75	
76	      const count = generationRule.count;
77	      if (count) {
78	        qb.limit(count);
79	      }
80	
81	      questions = await qb.getMany();
82	    }
83	
84	    const paper = this.paperRepo.create({
85	      name: dto.name,
86	      generation_rule: generationRule as any,
87	      created_by: userId,
88	      store_id: storeId ?? null,
89	    });
90	
91	    const savedPaper = await this.paperRepo.save(paper);
92	
93	    const paperQuestions = questions.map((q, index) =>
94	      this.paperQuestionRepo.create({
95	        paper_id: savedPaper.id,
96	        question_id: q.id,
97	        position: index + 1,
98	      }),
99	    );
100	
101	    await this.paperQuestionRepo.save(paperQuestions);
102	    savedPaper.paper_questions = paperQuestions;
103	
104	    return savedPaper;
105	  }
106	
107	  async startAttempt(paperId: string, userId: string): Promise<Attempt> {
108	    const paper = await this.paperRepo.findOne({ where: { id: paperId } });
109	    if (!paper) {
110	      throw new NotFoundException('Paper not found');
111	    }
112	
113	    const attempt = this.attemptRepo.create({
114	      paper_id: paperId,
115	      user_id: userId,
116	      status: AttemptStatus.IN_PROGRESS,
117	      started_at: new Date(),
118	    });
119	
120	    return this.attemptRepo.save(attempt);
121	  }
122	
123	  async submitAttempt(
124	    attemptId: string,
125	    answers: SubmitAnswerDto[],
126	    userId: string,
127	  ): Promise<Attempt> {
128	    const attempt = await this.attemptRepo.findOne({
129	      where: { id: attemptId },
130	    });
131	
132	    if (!attempt) {
133	      throw new NotFoundException('Attempt not found');
134	    }
135	
136	    if (attempt.user_id !== userId) {
137	      throw new BadRequestException('Attempt does not belong to this user');
138	    }
139	
140	    if (attempt.status !== AttemptStatus.IN_PROGRESS) {
141	      throw new BadRequestException('Attempt is not in progress');
142	    }
143	
144	    const now = new Date();
145	    let correctCount = 0;
146	    let totalObjective = 0;
147	    const attemptAnswers: AttemptAnswer[] = [];
148	
149	    for (const ans of answers) {
150	      const question = await this.questionRepo.findOne({
151	        where: { id: ans.questionId },
152	      });
153	
154	      if (!question) {
155	        throw new NotFoundException(`Question ${ans.questionId} not found`);
156	      }
157	
158	      let isCorrect: boolean | null = null;
159	
160	      if (question.type === QuestionType.OBJECTIVE) {
161	        totalObjective++;
162	
163	        if (ans.selectedOptionId) {
164	          const option = await this.optionRepo.findOne({
165	            where: { id: ans.selectedOptionId },
166	          });
167	
168	          if (option) {
169	            isCorrect = option.is_correct;
170	            if (isCorrect) {
171	              correctCount++;
172	            }
173	          } else {
174	            isCorrect = false;
175	          }
176	        } else {
177	          isCorrect = false;
178	        }
179	      }
180	      // subjective: is_correct remains null
181	
182	      const attemptAnswer = this.answerRepo.create({
183	        attempt_id: attemptId,
184	        question_id: ans.questionId,
185	        selected_option_id: ans.selectedOptionId ?? null,
186	        text_answer: ans.textAnswer ?? null,
187	        is_correct: isCorrect,
188	      });
189	
190	      attemptAnswers.push(attemptAnswer);
191	    }
192	
193	    await this.answerRepo.save(attemptAnswers);
194	
195	    const score =
196	      totalObjective > 0
197	        ? Math.round((correctCount / totalObjective) * 10000) / 100
198	        : null;
199	
200	    attempt.status = AttemptStatus.GRADED;
201	    attempt.graded_at = now;
202	    attempt.submitted_at = now;
203	    attempt.score = score;
204	    attempt.answers = attemptAnswers;
205	
206	    return this.attemptRepo.save(attempt);
207	  }
208	
209	  async redoAttempt(attemptId: string, userId: string): Promise<Attempt> {
210	    const original = await this.attemptRepo.findOne({
211	      where: { id: attemptId },
212	    });
213	
214	    if (!original) {
215	      throw new NotFoundException('Attempt not found');
216	    }
217	
218	    if (original.user_id !== userId) {
219	      throw new BadRequestException('Attempt does not belong to this user');
220	    }
221	
222	    const newAttempt = this.attemptRepo.create({
223	      paper_id: original.paper_id,
224	      user_id: userId,
225	      parent_attempt_id: attemptId,
226	      status: AttemptStatus.IN_PROGRESS,
227	      started_at: new Date(),
228	    });
229	
230	    return this.attemptRepo.save(newAttempt);
231	  }
232	
233	  async getHistory(userId: string): Promise<Attempt[]> {
234	    return this.attemptRepo.find({
235	      where: { user_id: userId },
236	      order: { started_at: 'DESC' },
237	      relations: ['paper'],
238	    });
239	  }
240	
241	  async getPapers(storeId?: string): Promise<Paper[]> {
242	    const where: any = {};
243	    if (storeId) {
244	      where.store_id = storeId;
245	    }
246	    return this.paperRepo.find({ where, relations: ['paper_questions'] });
247	  }
248	
249	  async getPaper(id: string): Promise<Paper> {
250	    const paper = await this.paperRepo.findOne({
251	      where: { id },
252	      relations: ['paper_questions', 'paper_questions.question', 'paper_questions.question.options'],
253	    });
254	
255	    if (!paper) {
256	      throw new NotFoundException('Paper not found');
257	    }
258	
259	    return paper;
260	  }
261	}
